    67	pub(crate) fn resolve_file_column_name(
    68	    input_schema: &Schema,
    69	    file_column_name: Option<&str>,
    70	) -> DeltaResult<String> {
    71	    let column_names: HashSet<&str> = input_schema
    72	        .fields()
    73	        .iter()
    74	        .map(|field| field.name().as_str())
    75	        .collect();
    76	
    77	    match file_column_name {
    78	        Some(name) => {
    79	            if column_names.contains(name) {
    80	                return Err(DeltaTableError::Generic(format!(
    81	                    "Unable to add file path column since column with name {name} exists"
    82	                )));
    83	            }
    84	
    85	            Ok(name.to_owned())
    86	        }
    87	        None => {
    88	            let prefix = PATH_COLUMN;
    89	            let mut idx = 0;
    90	            let mut name = prefix.to_owned();
    91	
    92	            while column_names.contains(name.as_str()) {
    93	                idx += 1;
    94	                name = format!("{prefix}_{idx}");
    95	            }
    96	
    97	            Ok(name)
    98	        }
    99	    }
