   347	/// Stream that produces logical RecordBatches from a Delta table scan.
   348	///
   349	/// Consumes raw Parquet data from the input stream and applies Delta Lake transformations
   350	/// per-file to yield logical table data. Handles:
   351	///
   352	/// - Deletion vectors: Filters rows marked as deleted
   353	/// - Column transforms: Applies partition value injection and column mapping
   354	/// - Schema projection: Projects to requested columns only
   355	/// - Type casting: Ensures output matches expected logical schema
   356	///
   357	/// Input batches may contain rows from multiple file IDs (e.g., due to upstream coalescing).
   358	/// The stream splits such batches by contiguous file-id runs and applies per-file transforms.
   359	struct DeltaScanStream {
   360	    scan_plan: Arc<KernelScanPlan>,
   361	    /// Kernel data type for the data after transformations
   362	    kernel_type: KernelDataType,
   363	    /// Input stream yielding raw data read from data files.
   364	    input: SendableRecordBatchStream,
   365	    /// Execution metrics
   366	    baseline_metrics: BaselineMetrics,
   367	    /// Transforms to be applied to data read from individual files
   368	    transforms: Arc<HashMap<String, ExpressionRef>>,
   369	    /// Selection vectors to be applied to data read from individual files
   370	    selection_vectors: Arc<DashMap<String, Vec<bool>>>,
   371	    /// Column name for the file id
   372	    file_id_column: String,
   373	    /// Denotes if file ids should be returned as part of the output
   374	    return_file_ids: bool,
   375	    pending: VecDeque<RecordBatch>,
   376	    /// Cached schema adapter for efficient batch adaptation across batches
   377	    schema_adapter: super::SchemaAdapter,
   378	}
