   126	    fn f_down(&mut self, node: &'_ Self::Node) -> Result<TreeNodeRecursion> {
   127	        match node {
   128	            Expr::IsNotNull(expr) => {
   129	                // we dont't actually need a kernel expression here, but DF field access
   130	                // if somewhat tedious to extract and the kernel ColumnName is convenient
   131	                // for this purpose.
