   364	    /// Create a new [`DataValidationExec`] if there are any predicates to apply
   365	    /// otherwise return the input execution plan as-is.
   366	    pub fn try_new_with_predicates(
   367	        session: &dyn Session,
   368	        input: Arc<dyn ExecutionPlan>,
   369	        predicates: Vec<Expr>,
   370	    ) -> Result<Arc<dyn ExecutionPlan>> {
   371	        let df_schema = DFSchema::try_from(input.schema())?;
   372	        if let Some(validation_expr) = conjunction(simplify_predicates(predicates)?) {
   373	            let check_expression = simplify_expr(session, df_schema.into(), validation_expr)?;
   374	            return Ok(Arc::new(Self::try_new(input, check_expression, None)?));
   375	        }
   376	        Ok(input)
   377	    }
