   379	    pub(crate) fn try_new_with_predicates_and_schema(
   380	        session: &dyn Session,
   381	        input: Arc<dyn ExecutionPlan>,
   382	        predicates: Vec<Expr>,
   383	        validated_schema: SchemaRef,
   384	    ) -> Result<Arc<dyn ExecutionPlan>> {
   385	        let df_schema = DFSchema::try_from(input.schema())?;
   386	        if let Some(validation_expr) = conjunction(simplify_predicates(predicates)?) {
   387	            let check_expression = simplify_expr(session, df_schema.into(), validation_expr)?;
   388	            return Ok(Arc::new(Self::try_new(
   389	                input,
   390	                check_expression,
   391	                Some(validated_schema),
   392	            )?));
   393	        }
   394	        Ok(input)
