   399	        input: Arc<dyn ExecutionPlan>,
   400	        check_expression: Arc<dyn PhysicalExpr>,
   401	        validated_schema: Option<SchemaRef>,
   402	    ) -> Result<Self> {
   403	        let result_type = check_expression.data_type(input.schema().as_ref())?;
   404	        if !matches!(result_type, DataType::Boolean) {
   405	            return plan_err!(
   406	                "Data validation expression must return boolean values, got {:?}",
   407	                result_type
   408	            );
   409	        }
   410	        let schema = validated_schema.unwrap_or_else(|| input.schema());
   411	        let properties = PlanProperties::new(
   412	            EquivalenceProperties::new(schema),
   413	            input.properties().partitioning.clone(),
   414	            input.properties().emission_type,
   415	            input.properties().boundedness,
   416	        );
   417	        Ok(Self {
   418	            input,
   419	            check_expression,
   420	            properties,
   421	        })
   422	    }
   423	}
