                    "MERGE duplicate match check encountered a null target row id".to_string(),
                ))));
            }

            let file_name = file_dictionary.values().value(file_key as usize).to_string();
            let row_id = row_ids.value(idx);
            if !self.seen.insert((file_name, row_id)) {
                return Err(DataFusionError::External(Box::new(DeltaTableError::Generic(
                    "MERGE operation failed: multiple source rows matched the same target row"
                        .to_string(),
                ))));
            }
        }

        Ok(())
    }
