struct MergeTargetRowIdStream {
    schema: SchemaRef,
    input: SendableRecordBatchStream,
    file_column: Arc<String>,
    row_id_column: Arc<String>,
    counters: Arc<dashmap::DashMap<String, u64>>,
}

impl MergeTargetRowIdStream {
    pub fn new(
        input: SendableRecordBatchStream,
        schema: SchemaRef,
        file_column: Arc<String>,
        row_id_column: Arc<String>,
        counters: Arc<dashmap::DashMap<String, u64>>,
    ) -> Self {
        Self {
            schema,
            input,
            file_column,
            row_id_column,
            counters,
        }
    }

    fn assign_row_ids(&self, batch: RecordBatch) -> DataFusionResult<RecordBatch> {
        let row_id_idx = batch.schema().index_of(self.row_id_column.as_str())?;
        let file_dictionary = get_path_column(&batch, &self.file_column)
            .map_err(|err| DataFusionError::External(Box::new(err)))?;
        let mut row_ids = UInt64Builder::with_capacity(batch.num_rows());

        for key in file_dictionary.keys().iter() {
            let Some(value) = key else {
                return Err(DataFusionError::External(Box::new(
                    DeltaTableError::Generic(
                        "MERGE target row id assignment encountered a null file path".to_string(),
                    ),
                )));
            };
            let file_name = file_dictionary.values().value(value as usize);
            let mut next_id = self.counters.entry(file_name.to_string()).or_insert(0);
            row_ids.append_value(*next_id);
            *next_id += 1;
        }

        let (schema, mut columns, _) = batch.into_parts();
        columns[row_id_idx] = Arc::new(row_ids.finish());
        Ok(RecordBatch::try_new(schema, columns)?)
    }
}

impl Stream for MergeTargetRowIdStream {
    type Item = DataFusionResult<RecordBatch>;

    fn poll_next(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
        match self.input.poll_next_unpin(cx) {
            Poll::Ready(Some(Ok(batch))) => Poll::Ready(Some(self.assign_row_ids(batch))),
            Poll::Ready(Some(Err(err))) => Poll::Ready(Some(Err(err))),
            Poll::Ready(None) => Poll::Ready(None),
            Poll::Pending => Poll::Pending,
        }
    }

    fn size_hint(&self) -> (usize, Option<usize>) {
        self.input.size_hint()
    }
}

