struct MergeDuplicateMatchCheckStream {
    schema: SchemaRef,
    input: SendableRecordBatchStream,
    file_column: Arc<String>,
    row_id_column: Arc<String>,
    seen: HashSet<(String, u64)>,
}

impl MergeDuplicateMatchCheckStream {
    pub fn new(
        input: SendableRecordBatchStream,
        schema: SchemaRef,
        file_column: Arc<String>,
        row_id_column: Arc<String>,
    ) -> Self {
        Self {
            schema,
            input,
            file_column,
            row_id_column,
            seen: HashSet::new(),
        }
    }

    fn check_batch(&mut self, batch: &RecordBatch) -> DataFusionResult<()> {
        let source = boolean_column(batch, SOURCE_COLUMN)?;
        let target = boolean_column(batch, TARGET_COLUMN)?;
        let row_ids = batch
            .column_by_name(self.row_id_column.as_str())
            .ok_or_else(|| {
                DataFusionError::External(Box::new(DeltaTableError::Generic(
                    "Required MERGE target row id column is missing".to_string(),
                )))
            })?
            .as_any()
            .downcast_ref::<UInt64Array>()
            .ok_or_else(|| {
                DataFusionError::External(Box::new(DeltaTableError::Generic(
                    "MERGE target row id column must be UInt64".to_string(),
                )))
            })?;
        let file_dictionary = get_path_column(batch, &self.file_column)
            .map_err(|err| DataFusionError::External(Box::new(err)))?;

        for idx in 0..batch.num_rows() {
            if !is_true(source, idx) || !is_true(target, idx) {
                continue;
            }

            let Some(file_key) = file_dictionary.keys().value(idx) else {
                return Err(DataFusionError::External(Box::new(
                    DeltaTableError::Generic(
                        "MERGE duplicate match check encountered a null file path".to_string(),
                    ),
                )));
            };

            if row_ids.is_null(idx) {
                return Err(DataFusionError::External(Box::new(
                    DeltaTableError::Generic(
                        "MERGE duplicate match check encountered a null target row id".to_string(),
                    ),
                )));
            }

            let file_name = file_dictionary
                .values()
                .value(file_key as usize)
                .to_string();
            let row_id = row_ids.value(idx);
            if !self.seen.insert((file_name, row_id)) {
                return Err(DataFusionError::External(Box::new(
                    DeltaTableError::Generic(
                        "MERGE operation failed: multiple source rows matched the same target row"
                            .to_string(),
                    ),
                )));
            }
        }

        Ok(())
    }
}

impl Stream for MergeDuplicateMatchCheckStream {
    type Item = DataFusionResult<RecordBatch>;

    fn poll_next(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
        match self.input.poll_next_unpin(cx) {
            Poll::Ready(Some(Ok(batch))) => match self.check_batch(&batch) {
                Ok(()) => Poll::Ready(Some(Ok(batch))),
                Err(err) => Poll::Ready(Some(Err(err))),
            },
            Poll::Ready(Some(Err(err))) => Poll::Ready(Some(Err(err))),
            Poll::Ready(None) => Poll::Ready(None),
            Poll::Pending => Poll::Pending,
        }
    }

    fn size_hint(&self) -> (usize, Option<usize>) {
        self.input.size_hint()
    }
}

impl RecordBatchStream for MergeDuplicateMatchCheckStream {
    fn schema(&self) -> SchemaRef {
        self.schema.clone()
    }
}

fn boolean_column<'a>(batch: &'a RecordBatch, column: &str) -> DataFusionResult<&'a BooleanArray> {
    batch
        .column_by_name(column)
        .ok_or_else(|| {
            DataFusionError::External(Box::new(DeltaTableError::Generic(format!(
                "Required MERGE column {column} is missing"
            ))))
        })?
        .as_any()
        .downcast_ref::<BooleanArray>()
        .ok_or_else(|| {
            DataFusionError::External(Box::new(DeltaTableError::Generic(format!(
                "MERGE column {column} must be Boolean"
            ))))
        })
}

fn is_true(array: &BooleanArray, idx: usize) -> bool {
    array.is_valid(idx) && array.value(idx)
}

