+fn resolve_internal_column_name(schemas: &[&DFSchema], prefix: &str) -> String {
+    let column_names: HashSet<&str> = schemas
+        .iter()
+        .flat_map(|schema| schema.fields().iter().map(|field| field.name().as_str()))
+        .collect();
+
+    let mut idx = 0;
+    let mut name = prefix.to_owned();
+    while column_names.contains(name.as_str()) {
+        idx += 1;
+        name = format!("{prefix}_{idx}");
+    }
+
+    name
+}
